        return (char)0xff;
    }

    /* Calculate target position */
    int target_pos = text_offset + char_index;

    /* Verify target position is within document bounds */
    if (target_pos >= doc_size) {
        return (char)0xff;
    }

    /* Safe to access the character */
    return (char)doc_data[target_pos];
}
